def alphabet_war(fight):
    powers = {
        'w': 4, 'p': 3, 'b': 2, 's': 1,
        'm': -4, 'q': -3, 'd': -2, 'z': -1
    }
    n = len(fight)
    if n == 0:
        return "Let's fight again!"
    destroyed = [False] * n
    for i in range(n):
        if fight[i] == '*':
            if i - 1 >= 0:
                destroyed[i - 1] = True
            destroyed[i] = True
            if i + 1 < n:
                destroyed[i + 1] = True
    total = 0
    for i in range(n):
        if not destroyed[i] and fight[i] in powers:
            total += powers[fight[i]]
    if total > 0:
        return "Left side wins!"
    elif total < 0:
        return "Right side wins!"
    else:
        return "Let's fight again!"

