def proper_fractions(n):
    if n < 2:
        return 0
    phi = n
    # Handle 2 separately
    if n % 2 == 0:
        phi //= 2
        while n % 2 == 0:
            n //= 2
    # Odd primes
    p = 3
    while p * p <= n:
        if n % p == 0:
            phi = (phi // p) * (p - 1)
            while n % p == 0:
                n //= p
        p += 2
    # Remaining prime
    if n > 1:
        phi = (phi // n) * (n - 1)
    return phi

