def sum_digits(M):
    if M <= 0:
        return 0
    res = 0
    l = 1
    while True:
        start = 10 ** (l - 1)
        if start > M:
            break
        end = min(M, 10 ** l - 1)
        num = end - start + 1
        res += num * l
        l += 1
    return res

def total_length(K):
    if K <= 0:
        return 0
    res = 0
    l = 1
    while True:
        start = 10 ** (l - 1)
        if start > K:
            break
        end = min(K, 10 ** l - 1)
        num = end - start + 1
        sum_cnt = num * (K + 1 - start) - (num * (num - 1) // 2)
        res += l * sum_cnt
        l += 1
    return res

def find_K(n):
    low = 1
    high = 2 * 10**9
    while low < high:
        mid = (low + high) // 2
        if total_length(mid) >= n:
            high = mid
        else:
            low = mid + 1
    return low

def find_m(K, pos):
    low = 1
    high = K
    while low < high:
        mid = (low + high) // 2
        if sum_digits(mid) >= pos:
            high = mid
        else:
            low = mid + 1
    return low

